using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ReturnsFailed()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ReturnsFailed()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -10m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await _gateway.ChargeAsync(null!, 25.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("", 25.00m);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccessfully()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailed()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_UniqueChargeIds_AcrossMultipleCalls()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }
}

[TestClass]
public sealed class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.RefundId));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync("");
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailed()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_SuccessfulRefund_HasUniqueRefundId()
    {
        var result1 = await _gateway.RefundAsync("ch_valid_123");
        var result2 = await _gateway.RefundAsync("ch_valid_456");

        Assert.AreNotEqual(result1.RefundId, result2.RefundId);
    }
}

